// Parse the fetched HTML
const inputUrl = $('Webhook').first().json.body.url || 'https://example.com';
let html = '';
let statusCode = 0;
let fetchSuccess = false;

try {
  const httpData = $input.first().json;
  // The HTTP Request node with full response returns body, headers, statusCode
  if (httpData.body) {
    html = typeof httpData.body === 'string' ? httpData.body : JSON.stringify(httpData.body);
    statusCode = httpData.statusCode || 200;
    fetchSuccess = true;
  } else if (httpData.data) {
    html = typeof httpData.data === 'string' ? httpData.data : JSON.stringify(httpData.data);
    statusCode = 200;
    fetchSuccess = true;
  } else if (typeof httpData === 'string') {
    html = httpData;
    statusCode = 200;
    fetchSuccess = true;
  } else {
    // Maybe the response is the HTML directly in one of the fields
    html = JSON.stringify(httpData).substring(0, 5000);
    fetchSuccess = true;
  }
} catch (e) {
  html = '';
  fetchSuccess = false;
}

if (!fetchSuccess || html.length < 50) {
  return [{
    json: {
      url: inputUrl,
      title: 'Could not fetch - site may be down or blocking requests',
      description: 'Failed to fetch website data',
      h1: 'N/A',
      statusCode: statusCode,
      stats: { images: 0, links: 0, scripts: 0, styles: 0, divs: 0, pageSizeKB: 0 },
      tech: 'Unknown',
      mobileReady: false,
      fetchSuccess: false
    }
  }];
}

// Extract basic info with regex
const titleMatch = html.match(/<title[^>]*>(.*?)<\/title>/is);
const title = titleMatch ? titleMatch[1].replace(/<[^>]+>/g, '').trim().substring(0, 200) : 'No title found';

const descMatch = html.match(/<meta[^>]*name=["']description["'][^>]*content=["'](.*?)["']/is) 
  || html.match(/<meta[^>]*content=["'](.*?)["'][^>]*name=["']description["']/is);
const description = descMatch ? descMatch[1].trim().substring(0, 300) : 'No meta description';

const h1Match = html.match(/<h1[^>]*>(.*?)<\/h1>/is);
const h1 = h1Match ? h1Match[1].replace(/<[^>]+>/g, '').trim().substring(0, 200) : 'No H1 tag found';

// Count elements
const imgCount = (html.match(/<img/gi) || []).length;
const linkCount = (html.match(/<a\s/gi) || []).length;
const scriptCount = (html.match(/<script/gi) || []).length;
const styleCount = (html.match(/<style/gi) || []).length;
const divCount = (html.match(/<div/gi) || []).length;
const formCount = (html.match(/<form/gi) || []).length;
const buttonCount = (html.match(/<button/gi) || []).length;

// Check for common frameworks/technologies
const techStack = [];
if (html.includes('react') || html.includes('__next') || html.includes('_next')) techStack.push('React/Next.js');
if (html.includes('wp-content') || html.includes('wordpress')) techStack.push('WordPress');
if (html.includes('bootstrap')) techStack.push('Bootstrap');
if (html.includes('tailwind')) techStack.push('Tailwind CSS');
if (html.includes('jquery') || html.includes('jQuery')) techStack.push('jQuery');
if (html.includes('vue') || html.includes('__vue')) techStack.push('Vue.js');
if (html.includes('angular')) techStack.push('Angular');
if (html.includes('shopify')) techStack.push('Shopify');
if (html.includes('squarespace')) techStack.push('Squarespace');
if (html.includes('wix')) techStack.push('Wix');

const hasViewport = html.includes('viewport');
const pageSize = Math.round(html.length / 1024);

// Check for some fun things
const hasInlineStyles = (html.match(/style="/gi) || []).length;
const hasFavicon = html.includes('favicon') || html.includes('icon');
const hasOpenGraph = html.includes('og:');

return [{
  json: {
    url: inputUrl,
    title: title,
    description: description,
    h1: h1,
    statusCode: statusCode,
    stats: {
      images: imgCount,
      links: linkCount,
      scripts: scriptCount,
      styles: styleCount,
      divs: divCount,
      forms: formCount,
      buttons: buttonCount,
      pageSizeKB: pageSize,
      inlineStyles: hasInlineStyles
    },
    tech: techStack.length > 0 ? techStack.join(', ') : 'Could not detect specific frameworks',
    mobileReady: hasViewport,
    hasFavicon: hasFavicon,
    hasOpenGraph: hasOpenGraph,
    fetchSuccess: true
  }
}];

